n      // 4b825…  == the empty tree used by git\n      baseOids.push('4b825dc642cb6eb9a060e54bf8d69288fbee4904');\n    } else {\n      // TODO: Recursive Merge strategy\n      throw new MergeNotSupportedError()\n    }\n  }\n  const baseOid = baseOids[0];\n  // handle fast-forward case\n  if (baseOid === theirOid) {\n    return {\n      oid: ourOid,\n      alreadyMerged: true,\n    }\n  }\n  if (fastForward && baseOid === ourOid) {\n    if (!dryRun && !noUpdateBranch) {\n      await GitRefManager.writeRef({ fs, gitdir, ref: ours, value: theirOid });\n    }\n    return {\n      oid: theirOid,\n      fastForward: true,\n    }\n  } else {\n    // not a simple fast-forward\n    if (fastForwardOnly) {\n      throw new FastForwardError()\n    }\n    // try a fancier merge\n    const tree = await GitIndexManager.acquire(\n      { fs, gitdir, cache, allowUnmerged: false },\n      async index => {\n        return mergeTree({\n          fs,\n          cache,\n          dir,\n          gitdir,\n          index,\n          ourOid,\n          theirOid,\n          baseOid,\n          ourName: abbreviateRef(ours),\n          baseName: 'base',\n          theirName: abbreviateRef(theirs),\n          dryRun,\n          abortOnConflict,\n          mergeDriver,\n        })\n      }\n    );\n\n    // Defer throwing error until the index lock is relinquished and index is\n    // written to filesystem\n    if (tree instanceof MergeConflictError) throw tree\n\n    if (!message) {\n      message = `Merge branch '${abbreviateRef(theirs)}' into ${abbreviateRef(\n        ours\n      )}`;\n    }\n    const oid = await _commit({\n      fs,\n      cache,\n      gitdir,\n      message,\n      ref: ours,\n      tree,\n      parent: [ourOid, theirOid],\n      author,\n      committer,\n      signingKey,\n      onSign,\n      dryRun,\n      noUpdateBranch,\n    });\n    return {\n      oid,\n      tree,\n      mergeCommit: true,\n    }\n  }\n}\n\n// @ts-check\n\n/**\n * @param {object} args\n * @param